example.code:
import pytest

# Default — fast, handles 95% of tests
@pytest.mark.django_db
def test_create_order(order_factory):
    order = order_factory(status="pending")
    assert order.status == "pending"

# transaction=True — only for on_commit callbacks
@pytest.mark.django_db(transaction=True)
def test_order_confirmation_email(order_factory, mailoutbox):
    order = order_factory(status="pending")
    order.confirm()  # Triggers on_commit → sends email
    assert len(mailoutbox) == 1
